# ── Data loading ───────────────────────────────────────────────────────────────


def load_tracker() -> dict | None:
    """Load the tracker JSON. Returns None if missing."""
    tracker_data, _ = load_effective_tracker_state(STATE_FILE, ARCHIVED_STATE_FILE)
    return tracker_data


def load_tracker_state() -> tuple[dict | None, dict[str, object], str | None]:
    """Load tracker data while preserving malformed-file context for UX flows."""
    try:
        tracker_data, tracker_integrity = load_effective_tracker_state(
            STATE_FILE, ARCHIVED_STATE_FILE
        )
    except (OSError, ValueError, json.JSONDecodeError) as exc:
        return None, default_tracker_integrity(), f"Tracker could not be loaded: {exc}"
    if tracker_data is None:
        return (
            None,
            default_tracker_integrity(),
            f"Tracker file not found at {STATE_FILE}",
        )
    return tracker_data, tracker_integrity, None


def count_trust_levels(artifacts: list[dict], artifact_type: str) -> dict[str, int]:
    """Count migrated artifacts by trust level for a specific artifact type."""
    counts = {
        "trusted_recent": 0,
        "legacy_unverified": 0,
    }
    for artifact in artifacts:
        if artifact.get("artifact_type") != artifact_type:
            continue
        if artifact.get("status") != "migrated":
            continue
        trust_level = artifact.get("trust_level")
        if trust_level in counts:
            counts[trust_level] += 1
    return counts


def count_review_states(artifacts: list[dict], artifact_type: str) -> dict[str, int]:
    """Count nativeness-review lifecycle states for an artifact type."""
    counts = {
        "pending_native_review": 0,
        "codex_compatible_but_not_native": 0,
        "native": 0,
        "not_applicable": 0,
    }
    for artifact in artifacts:
        if artifact.get("artifact_type") != artifact_type:
            continue
        review_state = artifact.get("review", {}).get("state", "not_applicable")
        if review_state in counts:
            counts[review_state] += 1
    return counts


# ── Tier classification ────────────────────────────────────────────────────────


def classify_skill_tier(name: str) -> tuple[int, list[str]]:
    """Classify a Claude skill into tier 1/2/3 based on SKILL.md content signals.

    Returns (tier, signals) where signals are the matched marker strings.
    Tier 0 = unclassifiable (SKILL.md not found).
    """
    skill_md = SOURCE_SKILLS_DIR / name / "SKILL.md"
    if not skill_md.exists():
        return (0, ["skill_md_not_found"])

    content = skill_md.read_text(encoding="utf-8", errors="ignore")

    # Count distinct MCP server families (mcp__foo__bar → "foo")
    mcp_families = set(re.findall(r"mcp__([a-z0-9_-]+)__", content))

    signals: list[str] = []

    skill_call_count = len(_SKILL_CALL_RE.findall(content))
    if skill_call_count:
        signals.append(f"DEP:Skill_calls={skill_call_count}")

    # Tier 3 check
    for marker in _TIER3_SIGNALS:
        if marker in content:
            signals.append(f"T3:{marker}")
    if len(mcp_families) >= 4:
        signals.append(f"T3:mcp_families={len(mcp_families)}")

    if any(s.startswith("T3:") for s in signals):
        return (3, signals)

    # Tier 2 check
    for marker in _TIER2_SIGNALS:
        if marker in content:
            signals.append(f"T2:{marker}")
    if "Bash" in content and "allowed-tools" in content:
        signals.append("T2:Bash_in_allowed_tools")
    if len(mcp_families) >= 2:
        signals.append(f"T2:mcp_families={len(mcp_families)}")

    if any(s.startswith("T2:") for s in signals):
        return (2, signals)

    return (1, [*signals, "T1:read_only_pattern"])


# ── Dependency extraction ──────────────────────────────────────────────────────


def extract_skill_deps(name: str) -> set[str]:
    """Return skill names referenced via Skill('x') calls in a Claude skill's files."""
    skill_dir = SOURCE_SKILLS_DIR / name
    if not skill_dir.exists():
        return set()

    deps: set[str] = set()
    for fpath in skill_dir.rglob("*"):
        if not fpath.is_file():
            continue
        try:
            text = fpath.read_text(encoding="utf-8", errors="ignore")
        except OSError:
            continue
        for m in _SKILL_CALL_RE.finditer(text):
            dep = m.group(1)
            if dep != name:
                deps.add(dep)

    return deps


def extract_agent_skill_deps(name: str) -> set[str]:
    """Return skill names listed in the Claude agent's skills: frontmatter."""
    agent_path = SOURCE_AGENTS_DIR / f"{name}.md"
    if not agent_path.exists():
        return set()

    try:
        content = agent_path.read_text(encoding="utf-8", errors="ignore")
    except OSError:
        return set()

    deps: set[str] = set()
    in_skills = False
    for line in content.splitlines():
        if line.strip() == "skills:":
            in_skills = True
            continue
        if in_skills:
            # YAML list item under skills:
            m = re.match(r"^\s+-\s+(.+)", line)
            if m:
                deps.add(m.group(1).strip())
            elif line and not line[0].isspace():
                # Left-indent = new key, skills: block ended
                break

    return deps


# ── Drift detection ────────────────────────────────────────────────────────────


def _compute_sha256(paths: list[Path]) -> str:
    """SHA-256 of sorted file contents — mirrors compute_version() in tracker."""
    hasher = hashlib.sha256()
    for path in sorted(paths):
        if path.exists():
            hasher.update(path.read_bytes())
    return hasher.hexdigest()


def _tracked_files_for(name: str, artifact_type: str) -> list[Path]:
    """Return the tracked files for an artifact (mirrors tracker version inputs)."""
    if artifact_type == "skill":
        paths: list[Path] = []
        claude_dir = SOURCE_SKILLS_DIR / name
        if claude_dir.exists():
            paths.extend(sorted(p for p in claude_dir.rglob("*") if p.is_file()))
        codex_dir = TARGET_SKILLS_DIR / name
        if codex_dir.exists():
            paths.extend(sorted(p for p in codex_dir.rglob("*") if p.is_file()))
        return sorted(paths)
    else:
        paths: list[Path] = []
        claude_path = SOURCE_AGENTS_DIR / f"{name}.md"
        if claude_path.exists():
            paths.append(claude_path)
        for suffix in (".toml", ".md"):
            codex_path = REPO_ROOT / ".codex" / "agents" / f"{name}{suffix}"
            if codex_path.exists():
                paths.append(codex_path)
        if paths:
            return sorted(paths)
    return []


def detect_drift(artifacts: list[dict]) -> list[dict]:
    """Find migrated artifacts whose tracked files changed since last tracker write.

    Returns list of {artifact_id, name, artifact_type, stored_sha, current_sha}.
    """
    drifted = []
    for a in artifacts:
        if a["status"] not in {"migrated", "native_codex"}:
            continue
        stored_sha = a["version"]["content_sha256"]
        tracked_paths = _tracked_files_for(a["name"], a["artifact_type"])
        current_sha = _compute_sha256(tracked_paths)
        if current_sha != stored_sha:
            drifted.append(
                {
                    "artifact_id": a["artifact_id"],
                    "name": a["name"],
                    "artifact_type": a["artifact_type"],
                    "stored_sha": stored_sha[:12],
                    "current_sha": current_sha[:12],
                }
            )
    return drifted


# ── Velocity ───────────────────────────────────────────────────────────────────

_WINDOW_DAYS = 28


def compute_velocity(events: list[dict]) -> dict:
    """Compute migration velocity from the events timeline.

    Returns {count_window, per_week, eta_weeks, window_days}.
    """
    now = datetime.now(timezone.utc)
    window_migrations = 0
    total_migrations = 0

    for ev in events:
        if ev.get("event_type") == "status_changed" and ev.get("to_status") == "migrated":
            total_migrations += 1
            try:
                ts = datetime.fromisoformat(ev["timestamp"])
                age_days = (now - ts).total_seconds() / 86400
                if age_days <= _WINDOW_DAYS:
                    window_migrations += 1
            except (ValueError, KeyError):
                pass

    per_week = round(window_migrations / (_WINDOW_DAYS / 7), 1) if window_migrations > 0 else 0.0

    return {
        "count_window": window_migrations,
        "total_migrations": total_migrations,
        "per_week": per_week,
        "window_days": _WINDOW_DAYS,
    }


def eta_weeks(pending_count: int, per_week: float) -> str:
    """Return a human-readable ETA string."""
    if per_week == 0:
        return "N/A (no recent migrations)"
    weeks = pending_count / per_week
    if weeks <= 4:
        return f"~{round(weeks)} weeks"
    months = weeks / 4.33
    return f"~{round(months)} months ({round(weeks)} weeks)"


# ── Batch planning ─────────────────────────────────────────────────────────────


def build_batch_plan(
    tracker_data: dict,
    batch_size: int = 8,
    show_all_blocked: bool = False,
) -> dict:
    """Build next-batch recommendations based on dependency graph and tier.

    Returns:
      {
        "ready": [{"artifact_id", "name", "artifact_type", "tier", "signals",
                   "unblocks", "score"}],
        "blocked": [{"artifact_id", "name", "dependency", "dep_status"}],
        "ignored": [{"artifact_id", "name", "blocking_reason"}],
        "total_pending": int,
      }
    """
    artifacts_by_id = {a["artifact_id"]: a for a in tracker_data.get("artifacts", [])}
    pending_ids: set[str] = {
        a["artifact_id"]
        for a in tracker_data.get("artifacts", [])
        if a["status"] == "pending"
    }

    # Build dependency map: artifact_id → set of artifact_ids it depends on
    deps_map: dict[str, set[str]] = {}
    for a in tracker_data.get("artifacts", []):
        aid = a["artifact_id"]
        name = a["name"]
        atype = a["artifact_type"]

        if atype == "skill":
            raw_deps = extract_skill_deps(name)
        else:
            raw_deps = extract_agent_skill_deps(name)

        # Resolve dep names to artifact_ids that exist in tracker
        resolved: set[str] = set()
        for dep_name in raw_deps:
            skill_dep_id = f"skill:{dep_name}"
            if skill_dep_id in artifacts_by_id:
                resolved.add(skill_dep_id)
        deps_map[aid] = resolved

    # Reverse map: artifact_id → set of artifact_ids that depend on it
    reverse_deps: dict[str, set[str]] = defaultdict(set)
    for aid, deps in deps_map.items():
        for dep_id in deps:
            reverse_deps[dep_id].add(aid)

    ready: list[dict] = []
    blocked: list[dict] = []
    ignored: list[dict] = []

    for artifact in tracker_data.get("artifacts", []):
        if artifact["status"] == "ignored":
            ignored.append(
                {
                    "artifact_id": artifact["artifact_id"],
                    "name": artifact["name"],
                    "artifact_type": artifact["artifact_type"],
                    "blocking_reason": artifact.get("status_reason", "manual migration ignore"),
                    "all_blockers": 1,
                }
            )
            continue

        if artifact["status"] != "pending":
            continue

        aid = artifact["artifact_id"]
        name = artifact["name"]
        atype = artifact["artifact_type"]
        my_deps = deps_map.get(aid, set())

        # Check if any dependency is still pending (blocking)
        blocking_deps = [(dep_id, artifacts_by_id[dep_id]["status"]) for dep_id in my_deps if dep_id in pending_ids]

        if blocking_deps:
            dep_id, dep_status = blocking_deps[0]
            blocked.append(
                {
                    "artifact_id": aid,
                    "name": name,
                    "artifact_type": atype,
                    "blocking_dep": dep_id,
                    "dep_status": dep_status,
                    "all_blockers": len(blocking_deps),
                }
            )
        else:
            if atype == "skill":
                tier, signals = classify_skill_tier(name)
            else:
                tier, signals = (2, ["T2:agent"])

            unblocks_names = [
                artifacts_by_id[dep_of_me]["artifact_id"]
                for dep_of_me in reverse_deps.get(aid, set())
                if dep_of_me in pending_ids
            ]

            unblock_count = len(unblocks_names)
            score = (unblock_count * 10) + max(0, (4 - tier) * 3)

            ready.append(
                {
                    "artifact_id": aid,
                    "name": name,
                    "artifact_type": atype,
                    "tier": tier,
                    "signals": signals[:3],
                    "unblocks": unblocks_names,
                    "score": score,
                }
            )

    ready.sort(key=lambda x: (-x["score"], x["tier"], x["name"]))

    return {
        "ready": ready[:batch_size],
        "ready_total": len(ready),
        "blocked": blocked if show_all_blocked else blocked[:5],
        "blocked_total": len(blocked),
        "ignored": ignored,
        "ignored_total": len(ignored),
        "total_pending": len(pending_ids),
    }


# ── Validation ─────────────────────────────────────────────────────────────────


def run_validators(tracker_data: dict) -> list[dict]:
    """Run validate_names.py against each migrated skill.

    Returns list of {name, passed, output}.
    """
    if not VALIDATOR_SCRIPT.exists():
        return [{"name": "_error", "passed": None, "output": f"Validator not found: {VALIDATOR_SCRIPT}"}]

    results = []
    for a in tracker_data.get("artifacts", []):
        if a["status"] not in {"migrated", "native_codex"} or a["artifact_type"] != "skill":
            continue

        skill_dir = TARGET_SKILLS_DIR / a["name"]
        if not skill_dir.exists():
            results.append({"name": a["name"], "passed": False, "output": "no .codex/skills/ directory"})
            continue

        try:
            proc = subprocess.run(
                [sys.executable, str(VALIDATOR_SCRIPT), "--scan-dir", str(skill_dir)],
                capture_output=True,
                text=True,
                timeout=30,
                cwd=str(REPO_ROOT),
            )
            passed = proc.returncode == 0
            output = (proc.stdout + proc.stderr).strip()
            results.append({
                "name": a["name"],
                "passed": passed,
                "output": output[:200],
                "review_state": a.get("review", {}).get("state", "not_applicable"),
            })
        except subprocess.TimeoutExpired:
            results.append({
                "name": a["name"],
                "passed": None,
                "output": "timeout",
                "review_state": a.get("review", {}).get("state", "not_applicable"),
            })
        except OSError as e:
            results.append({
                "name": a["name"],
                "passed": None,
                "output": str(e),
                "review_state": a.get("review", {}).get("state", "not_applicable"),
            })

    return results


def run_environment_readiness_validation() -> dict[str, object]:
    """Run the migration validator's environment-readiness check once per dashboard pass."""
    if not VALIDATOR_SCRIPT.exists():
        return {
            "state": "not_applicable",
            "output": f"Validator not found: {VALIDATOR_SCRIPT}",
        }
    try:
        proc = subprocess.run(
            [
                sys.executable,
                str(VALIDATOR_SCRIPT),
                "--check",
                "environment-readiness",
                "--codex-home",
                str(REPO_ROOT / ".codex"),
            ],
            capture_output=True,
            text=True,
            timeout=30,
            cwd=str(REPO_ROOT),
        )
        output = (proc.stdout + proc.stderr).strip()
        if proc.returncode != 0:
            state = "failed"
        elif "Validation PASSED with warnings." in output:
            state = "warnings"
        else:
            state = "ok"
        return {"state": state, "output": output[:500]}
    except subprocess.TimeoutExpired:
        return {"state": "failed", "output": "timeout"}
    except OSError as exc:
        return {"state": "failed", "output": str(exc)}


