_WARNING_COUNT_RE = re.compile(r"Warnings \((\d+)\):")


def _bar(value: int, total: int, width: int = 24) -> str:
    filled = round(width * value / total) if total else 0
    return "█" * filled + "░" * (width - filled)


def _artifact_status_label(status: str) -> str:
    return _ARTIFACT_STATUS_LABELS.get(status, status)


def _review_state_label(review_state: str) -> str:
    return _REVIEW_STATE_LABELS.get(review_state, review_state)


def _warning_count(result: dict) -> int:
    output = result.get("output") or ""
    match = _WARNING_COUNT_RE.search(output)
    if match:
        return int(match.group(1))
    if output.startswith("Validation OK"):
        return 0
    return sum(1 for line in output.splitlines() if "⚠" in line)


def _actionable_pending_total(tracker_data: dict) -> int:
    summary = tracker_data.get("summary", {})
    return sum(
        summary.get(artifact_type, {}).get("pending", 0)
        + summary.get(artifact_type, {}).get("blocked", 0)
        for artifact_type in ("skill", "agent")
    )


def _pending_review_total(tracker_data: dict) -> int:
    return len(_nativeness_review_items(tracker_data))


def _review_backlog_is_primary_action(tracker_data: dict) -> bool:
    return _actionable_pending_total(tracker_data) == 0 and _pending_review_total(
        tracker_data
    ) > 0


def _recommended_action(
    *,
    key: str,
    label: str,
    reason: str,
    command: str | None = None,
    reply: str | None = None,
    artifact_id: str | None = None,
) -> dict[str, object]:
    payload: dict[str, object] = {
        "key": key,
        "label": label,
        "reason": reason,
    }
    if command is not None:
        payload["command"] = command
    if reply is not None:
        payload["reply"] = reply
    if artifact_id is not None:
        payload["artifact_id"] = artifact_id
    return payload


def _normalized_tracker_integrity(
    tracker_integrity: dict[str, object] | None,
) -> dict[str, object]:
    normalized = default_tracker_integrity()
    if tracker_integrity:
        normalized.update(tracker_integrity)
    normalized["recovered_review_artifact_ids"] = list(
        normalized.get("recovered_review_artifact_ids", [])
    )
    normalized["recovery_conflicts"] = list(normalized.get("recovery_conflicts", []))
    return normalized


def _tracker_integrity_blockers(
    tracker_integrity: dict[str, object],
) -> list[dict[str, str]]:
    if tracker_integrity.get("actionability") != "blocked":
        return []
    conflicts = tracker_integrity.get("recovery_conflicts", [])
    if conflicts:
        return [
            {
                "severity": "high",
                "type": "tracker_integrity",
                "detail": detail,
            }
            for detail in conflicts
        ]
    return [
        {
            "severity": "high",
            "type": "tracker_integrity",
            "detail": "Archived tracker recovery is ambiguous; repair the live tracker before using nativeness queues.",
        }
    ]


def _tracker_warning_lines(tracker_integrity: dict[str, object]) -> list[str]:
    if tracker_integrity.get("actionability") == "blocked":
        return [
            "Tracker review recovery is ambiguous; run "
            "`python3 tools/migration_support/tracker.py --write` before using nativeness queues."
        ]
    recovered_ids = tracker_integrity.get("recovered_review_artifact_ids", [])
    if recovered_ids:
        return [
            "Recovered archived nativeness reviews into the effective tracker view. "
            "Run `python3 tools/migration_support/tracker.py --write` to persist them."
        ]
    return []


def _nativeness_review_items(tracker_data: dict) -> list[dict]:
    """Return artifacts that are ready for nativeness review."""
    items: list[dict] = []
    for artifact in tracker_data.get("artifacts", []):
        if artifact.get("status") not in _NATIVE_REVIEWABLE_STATUSES:
            continue
        review_state = artifact.get("review", {}).get("state", "not_applicable")
        if review_state != _PENDING_NATIVE_REVIEW:
            continue

        item = {
            "artifact_id": artifact["artifact_id"],
            "name": artifact["name"],
            "artifact_type": artifact["artifact_type"],
            "status": artifact["status"],
            "review_state": review_state,
            "trust_level": artifact.get("trust_level", "not_applicable"),
        }
        if artifact["artifact_type"] == "skill":
            tier, signals = classify_skill_tier(artifact["name"])
            item["tier"] = tier
            item["tier_label"] = TIER_LABELS[tier]
            item["signals"] = signals[:3]
        items.append(item)
    return items


def build_review_backlog(tracker_data: dict) -> list[dict]:
    """Return nativeness backlog sorted by priority."""
    items = _nativeness_review_items(tracker_data)

    def sort_key(item: dict) -> tuple[int, int, int, str]:
        artifact_priority = 0 if item["artifact_type"] == "agent" else 1
        trust_priority = _TRUST_BACKLOG_PRIORITY.get(item.get("trust_level"), 2)
        skill_tier_priority = (
            _SKILL_TIER_BACKLOG_PRIORITY.get(item.get("tier", 0), 3)
            if item["artifact_type"] == "skill"
            else 0
        )
        return (artifact_priority, trust_priority, skill_tier_priority, item["name"])

    return sorted(items, key=sort_key)


def build_unreviewed_artifacts(tracker_data: dict) -> list[dict]:
    """Return all pending nativeness-review artifacts grouped by type then name."""
    items = _nativeness_review_items(tracker_data)
    return sorted(items, key=lambda item: (item["artifact_type"], item["name"]))


def build_agent_nativeness_queue(tracker_data: dict) -> list[dict]:
    """Return pending nativeness-review agents."""
    items = _nativeness_review_items(tracker_data)
    return sorted(
        (item for item in items if item["artifact_type"] == "agent"),
        key=lambda item: item["name"],
    )


def build_skill_nativeness_queue(tracker_data: dict) -> list[dict]:
    """Return pending nativeness-review skills."""
    items = _nativeness_review_items(tracker_data)
    return sorted(
        (item for item in items if item["artifact_type"] == "skill"),
        key=lambda item: item["name"],
    )


def _queue_window(items: list[dict]) -> list[dict]:
    """Return the items that should be shown in the current response."""
    if len(items) <= _QUEUE_SHOW_ALL_MAX:
        return list(items)
    return list(items[:_QUEUE_TRUNCATE_TO])


def _annotate_display_indices(items: list[dict]) -> list[dict]:
    annotated: list[dict] = []
    for index, item in enumerate(items, start=1):
        annotated.append({**item, "display_index": index})
    return annotated


def _selection_payload(
    displayed_items: list[dict],
    *,
    recommended_item: dict | None,
    tracker_integrity: dict[str, object],
) -> dict[str, object] | None:
    if not displayed_items:
        return None
    if tracker_integrity.get("actionability") == "blocked":
        return None
    examples = ["review next", f"review {min(3, len(displayed_items))}"]
    if recommended_item is not None:
        examples.append(f"review {recommended_item['name']}")
    examples.append("back")
    display_index_map = {
        str(item["display_index"]): item["artifact_id"] for item in displayed_items
    }
    return {
        "kind": "finite_named_queue",
        "recommended_item": recommended_item,
        "recommended_artifact_id": (
            recommended_item["artifact_id"] if recommended_item is not None else None
        ),
        "can_pick_by_index": True,
        "index_scope": "current_response_only",
        "displayed_artifact_ids": [item["artifact_id"] for item in displayed_items],
        "display_index_map": display_index_map,
        "queue_scope": "displayed_items_only",
        "recompute_after_action": False,
        "done_behavior": "queue_complete_requires_back",
        "reply_examples": examples,
    }


def _queue_prompt_lines(
    *,
    recommended_item: dict | None,
    truncated: bool,
    tracker_integrity: dict[str, object],
) -> list[str]:
    lines = ["", f"{_BOLD}NEXT ACTION{_RESET}"]
    if tracker_integrity.get("actionability") == "blocked":
        lines.append(
            "  Repair tracker state first: `python3 tools/migration_support/tracker.py --write`."
        )
        lines.append("  Use `back` to return to the dashboard menu.")
        return lines
    if recommended_item is not None:
        lines.append(
            "  Recommended: "
            f"`review next` for {recommended_item['artifact_type']}:{recommended_item['name']}"
        )
    lines.append("  Or pick one with `review <number>` or `review <name>`.")
    if truncated:
        lines.append("  If the item is not shown, use `review <exact-name>`.")
    lines.append("  Use `back` to return to the dashboard menu.")
    return lines


def _format_nativeness_item(item: dict) -> str:
    prefix = f"{item['artifact_type']}:"
    trust = item.get("trust_level", "not_applicable")
    artifact_status = _artifact_status_label(item.get("status", ""))
    review_state = _review_state_label(item.get("review_state", ""))
    detail = f"artifact={artifact_status}  review={review_state}  trust={trust}"
    if item["artifact_type"] == "skill":
        detail += f"  tier={item.get('tier_label', TIER_LABELS[0])}"
    return f"  {prefix}{item['name']:<34}  {detail}"


def format_status(
    tracker_data: dict,
    drifted: list[dict],
    velocity: dict,
    *,
    tracker_integrity: dict[str, object] | None = None,
) -> str:
    summary = tracker_data.get("summary", {})
    trust_policy = tracker_data.get("trust_policy", {})
    artifacts = tracker_data.get("artifacts", [])
    tracker_integrity = _normalized_tracker_integrity(tracker_integrity)
    lines: list[str] = []

    today = datetime.now(timezone.utc).strftime("%Y-%m-%d")
    lines.append(f"\n{_BOLD}Migration Dashboard — {today}{_RESET}")
    lines.append("━" * 60)

    lines.append(f"\n{_BOLD}PROGRESS{_RESET}")
    for atype in ("skill", "agent"):
        s = summary.get(atype, {})
        migrated = s.get("migrated", 0)
        redirected = s.get("redirected", 0)
        archived = s.get("archived", 0)
        native = s.get("native_codex", 0)
        pending = s.get("pending", 0)
        blocked = s.get("blocked", 0)
        ignored = s.get("ignored", 0)
        removed = s.get("removed", 0)
        done = migrated + native
        total = done + pending + blocked
        pct = round(100 * done / total) if total else 0
        bar = _bar(done, total)
        lines.append(
            f"  {atype.capitalize():6}  {done:3}/{total:3}  {bar}  {pct}%"
        )
        lines.append(
            f"           artifact lifecycle: pending: {pending}  │ migrated: {migrated}  │ "
            f"native: {native}  │ redirected: {redirected}  │ archived: {archived}"
        )
        if blocked:
            lines.append(f"           blocked: {blocked}")
        if ignored:
            lines.append(f"           ignored: {ignored}")
        if removed:
            lines.append(f"           removed: {removed}")
        review_counts = count_review_states(artifacts, atype)
        review_applicable = (
            review_counts["pending_native_review"]
            + review_counts["codex_compatible_but_not_native"]
            + review_counts["native"]
        )
        if review_applicable:
            lines.append(
                "           review lifecycle: "
                f"{review_counts['pending_native_review']} pending review  │ "
                f"{review_counts['codex_compatible_but_not_native']} compatible  │ "
                f"{review_counts['native']} reviewed native"
            )
        trust_counts = count_trust_levels(artifacts, atype)
        if migrated > 0:
            cutoff = trust_policy.get("recent_review_cutoff", "<migration-trust-cutoff-date>")
            lines.append(
                "           trust: "
                f"{trust_counts['trusted_recent']} trusted_recent  │ "
                f"{trust_counts['legacy_unverified']} legacy_unverified"
                f"  │ cutoff: {cutoff}"
            )

    skill_pending = [
        a for a in tracker_data.get("artifacts", [])
        if a["artifact_type"] == "skill" and a["status"] == "pending"
    ]
    if skill_pending:
        lines.append(f"\n{_BOLD}PENDING SKILLS — TIER BREAKDOWN{_RESET}")
        tier_counts: dict[int, int] = {1: 0, 2: 0, 3: 0, 0: 0}
        for a in skill_pending:
            tier, _ = classify_skill_tier(a["name"])
            tier_counts[tier] += 1

        for t in (1, 2, 3, 0):
            count = tier_counts[t]
            if count:
                label = TIER_LABELS[t]
                lines.append(f"  {label:22}  {count:3} skills")

    lines.append(f"\n{_BOLD}VELOCITY  (last {velocity['window_days']} days){_RESET}")
    if velocity["count_window"] > 0:
        all_pending = sum(
            a["status"] in {"pending", "blocked"}
            for a in tracker_data.get("artifacts", [])
        )
        lines.append(
            f"  {velocity['count_window']} migrations  →  {velocity['per_week']}/week"
        )
        lines.append(f"  ETA (skills + agents): {eta_weeks(all_pending, velocity['per_week'])}")
    else:
        lines.append(f"  {_YELLOW}No recent migrations tracked in events.{_RESET}")
        lines.append(
            f"  {_DIM}Tip: velocity is derived from tracker events. "
            f"If tracker was just initialized, events history is sparse.{_RESET}"
        )

    lines.append(f"\n{_BOLD}DRIFT ALERTS{_RESET}  (migrated artifacts whose tracked files changed)")
    if drifted:
        for d in drifted:
            atype_label = "skill" if d["artifact_type"] == "skill" else "agent"
            lines.append(
                f"  {_YELLOW}⚠{_RESET}  {atype_label}:{d['name']:<35}  "
                f"sha: {d['stored_sha']}→{d['current_sha']}"
            )
        lines.append(
            f"\n  {_DIM}Run /migrate-to-codex for drifted skills to re-sync .codex/ versions.{_RESET}"
        )
    else:
        lines.append(f"  {_GREEN}✓{_RESET}  No drift detected — all migrated tracked files match stored SHAs.")

    tracker_warnings = _tracker_warning_lines(tracker_integrity)
    if tracker_warnings:
        lines.append(f"\n{_BOLD}TRACKER INTEGRITY{_RESET}")
        for warning in tracker_warnings:
            lines.append(f"  {_YELLOW}⚠{_RESET}  {warning}")

    lines.append(f"\n{_BOLD}NEXT ACTION{_RESET}")
    if drifted:
        lines.append("  Recommended: re-run the relevant migration flow for drifted artifacts.")
    elif tracker_integrity.get("actionability") == "blocked":
        lines.append(
            "  Recommended: `python3 tools/migration_support/tracker.py --write`."
        )
    elif _review_backlog_is_primary_action(tracker_data):
        lines.append(
            "  Recommended: `python3 .codex/skills/migration-dashboard/scripts/analyze_migration.py --review-backlog`."
        )
    else:
        lines.append(
            "  Recommended: `python3 .codex/skills/migration-dashboard/scripts/analyze_migration.py --plan`."
        )
    lines.append(
        f"  {_DIM}Secondary: `python3 .codex/skills/migration-dashboard/scripts/analyze_migration.py --validate` or `--refresh`.{_RESET}"
    )

    return "\n".join(lines)


def format_plan(plan: dict, batch_size: int, *, pending_review_total: int = 0) -> str:
    lines: list[str] = []
    lines.append(f"\n{_BOLD}Next Batch Plan (batch-size: {batch_size}){_RESET}")
    lines.append("━" * 60)

    ready = plan["ready"]
    blocked = plan["blocked"]
    ignored = plan["ignored"]

    if not ready:
        lines.append(f"\n  {_YELLOW}No ready pending artifacts found.{_RESET}")
        if blocked:
            lines.append("  All pending artifacts have unmet dependencies — migrate blockers first.")
        elif plan["total_pending"] == 0:
            lines.append("  No actionable pending artifacts remain.")
            if pending_review_total:
                lines.append(
                    f"  Nativeness review backlog remains: {pending_review_total} artifact(s)."
                )
    else:
        lines.append(f"\n{_BOLD}READY{_RESET} — {plan['ready_total']} artifacts with no unmet dependencies (showing {len(ready)})")

        by_tier: dict[int, list[dict]] = defaultdict(list)
        for item in ready:
            by_tier[item["tier"]].append(item)

        rank = 1
        for tier in (1, 2, 3, 0):
            group = by_tier.get(tier, [])
            if not group:
                continue
            tier_label = TIER_LABELS[tier]
            lines.append(f"\n  {_BOLD}{tier_label}{_RESET}")
            for item in group:
                unblocks_str = ""
                if item["unblocks"]:
                    names = ", ".join(item["unblocks"][:3])
                    suffix = f" +{len(item['unblocks'])-3} more" if len(item["unblocks"]) > 3 else ""
                    unblocks_str = f"  {_GREEN}→ unblocks:{_RESET} {names}{suffix}"
                lines.append(f"  {rank:2}. {item['name']:<40}{unblocks_str}")
                rank += 1

    if blocked:
        lines.append(f"\n{_BOLD}BLOCKED{_RESET} — {plan['blocked_total']} artifacts have unmet dependencies (showing {len(blocked)})")
        for item in blocked:
            atype_prefix = f"{item['artifact_type']}:" if item["artifact_type"] == "agent" else ""
            extra = f" (+{item['all_blockers']-1} more)" if item["all_blockers"] > 1 else ""
            lines.append(
                f"  {_RED}x{_RESET}  {atype_prefix}{item['name']:<38}  needs: {item['blocking_dep']}{extra}"
            )
        if plan["blocked_total"] > len(blocked):
            remaining = plan["blocked_total"] - len(blocked)
            lines.append(f"  {_DIM}... and {remaining} more. Run --plan --all to see full list.{_RESET}")

    if ignored:
        lines.append(f"\n{_BOLD}IGNORED{_RESET} — {plan['ignored_total']} artifacts are intentionally excluded from migration")
        for item in ignored:
            atype_prefix = f"{item['artifact_type']}:" if item["artifact_type"] == "agent" else ""
            lines.append(
                f"  {_DIM}·{_RESET}  {atype_prefix}{item['name']:<38}  reason: {item['blocking_reason']}"
            )

    lines.append(f"\n{_BOLD}NEXT ACTION{_RESET}")
    if ready:
        top_item = ready[0]
        lines.append(
            f"  Recommended: migrate {top_item['artifact_type']}:{top_item['name']} first."
        )
    elif blocked:
        lines.append("  Recommended: resolve the first dependency blocker, then rerun planning.")
    elif pending_review_total:
        lines.append(
            "  Recommended: `python3 .codex/skills/migration-dashboard/scripts/analyze_migration.py --review-backlog`."
        )
    else:
        lines.append("  Recommended: no actionable migration work remains in this dashboard.")
    lines.append("")
    return "\n".join(lines)


def format_validate(
    results: list[dict],
    *,
    pending_review_total: int = 0,
    tracker_integrity: dict[str, object] | None = None,
    environment_readiness: dict[str, object] | None = None,
) -> str:
    tracker_integrity = _normalized_tracker_integrity(tracker_integrity)
    lines: list[str] = []
    lines.append(f"\n{_BOLD}Migration Quality Report{_RESET}")
    lines.append("━" * 60)

    passed = [r for r in results if r["passed"] is True]
    failed = [r for r in results if r["passed"] is False]
    unknown = [r for r in results if r["passed"] is None]

    total = len(results)
    lines.append(f"\n  Total migrated skills validated: {total}")
    lines.append(f"  {_GREEN}✓ Pass:{_RESET}  {len(passed)}")
    lines.append(f"  {_RED}✗ Fail:{_RESET}  {len(failed)}")
    lines.append(f"  {_YELLOW}? Skip:{_RESET}  {len(unknown)}")
    review_counts = {
        "pending_native_review": 0,
        "codex_compatible_but_not_native": 0,
        "native": 0,
        "not_applicable": 0,
    }
    for result in results:
        review_state = result.get("review_state", "not_applicable")
        if review_state in review_counts:
            review_counts[review_state] += 1
    if total:
        lines.append(
            "  Review lifecycle: "
            f"pending review={review_counts['pending_native_review']}  │ "
            f"compatible={review_counts['codex_compatible_but_not_native']}  │ "
            f"reviewed native={review_counts['native']}"
        )

    if environment_readiness:
        lines.append(
            "  Environment readiness: "
            f"{environment_readiness.get('state', 'not_applicable')}"
        )
        if environment_readiness.get("state") in {"failed", "warnings"}:
            for detail_line in str(environment_readiness.get("output", "")).splitlines()[:4]:
                lines.append(f"       {_DIM}{detail_line}{_RESET}")

    if failed:
        lines.append(f"\n{_BOLD}FAILURES{_RESET}")
        for r in failed:
            review_suffix = ""
            if r.get("review_state") and r.get("review_state") != "not_applicable":
                review_suffix = f"  [{_review_state_label(r['review_state'])}]"
            lines.append(f"  {_RED}✗{_RESET}  {r['name']}{review_suffix}")
            if r["output"]:
                for detail_line in r["output"].splitlines()[:5]:
                    lines.append(f"       {_DIM}{detail_line}{_RESET}")
    elif pending_review_total:
        lines.append(f"\n{_BOLD}NEXT REVIEW CANDIDATES{_RESET}")
        candidates = sorted(
            (
                result
                for result in results
                if result.get("review_state") == _PENDING_NATIVE_REVIEW
            ),
            key=lambda result: (-_warning_count(result), result["name"]),
        )[:5]
        for result in candidates:
            lines.append(
                f"  {_DIM}·{_RESET}  {result['name']:<35} warnings={_warning_count(result)}"
            )

    if unknown:
        lines.append(f"\n{_BOLD}SKIPPED (missing or timeout){_RESET}")
        for r in unknown:
            review_suffix = ""
            if r.get("review_state") and r.get("review_state") != "not_applicable":
                review_suffix = f"  [{_review_state_label(r['review_state'])}]"
            lines.append(f"  {_YELLOW}?{_RESET}  {r['name']}{review_suffix}  — {r['output']}")

    tracker_warnings = _tracker_warning_lines(tracker_integrity)
    if tracker_warnings:
        lines.append(f"\n{_BOLD}TRACKER INTEGRITY{_RESET}")
        for warning in tracker_warnings:
            lines.append(f"  {_YELLOW}⚠{_RESET}  {warning}")

    lines.append(f"\n{_BOLD}NEXT ACTION{_RESET}")
    if failed:
        lines.append("  Recommended: patch or re-migrate the failing skills before rollout.")
    elif tracker_integrity.get("actionability") == "blocked":
        lines.append(
            "  Recommended: `python3 tools/migration_support/tracker.py --write`."
        )
    elif pending_review_total:
        lines.append(
            "  Recommended: `python3 .codex/skills/migration-dashboard/scripts/analyze_migration.py --review-backlog`."
        )
    else:
        lines.append(
            "  Recommended: `python3 .codex/skills/migration-dashboard/scripts/analyze_migration.py --plan` if you want to inspect migration backlog."
        )
    lines.append("")
    return "\n".join(lines)


def format_review_backlog(
    items: list[dict],
    *,
    recommended_item: dict | None = None,
    tracker_integrity: dict[str, object] | None = None,
) -> str:
    tracker_integrity = _normalized_tracker_integrity(tracker_integrity)
    lines: list[str] = []
    lines.append(f"\n{_BOLD}Nativeness Review Backlog{_RESET}")
    lines.append("━" * 60)

    if not items:
        lines.append(f"\n  {_GREEN}✓{_RESET}  No pending nativeness review items remain.")
        lines.append("")
        return "\n".join(lines)

    displayed_items = _annotate_display_indices(_queue_window(items))
    lines.append(f"\n  Pending nativeness reviews: {len(items)}")
    lines.append("  Priority: agents first, then trust level, then skill tier.")

    for item in displayed_items:
        lines.append(f"  {item['display_index']:2}. {_format_nativeness_item(item).strip()}")

    tracker_warnings = _tracker_warning_lines(tracker_integrity)
    if tracker_warnings:
        lines.append(f"\n{_BOLD}TRACKER INTEGRITY{_RESET}")
        for warning in tracker_warnings:
            lines.append(f"  {_YELLOW}⚠{_RESET}  {warning}")

    lines.extend(
        _queue_prompt_lines(
            recommended_item=recommended_item,
            truncated=len(displayed_items) < len(items),
            tracker_integrity=tracker_integrity,
        )
    )

    lines.append("")
    return "\n".join(lines)


def format_unreviewed(
    items: list[dict],
    *,
    recommended_item: dict | None = None,
    tracker_integrity: dict[str, object] | None = None,
) -> str:
    tracker_integrity = _normalized_tracker_integrity(tracker_integrity)
