    if not items:
        lines.append(f"\n  {_GREEN}✓{_RESET}  No migrated artifacts are waiting on nativeness review.")
        lines.append("")
        return "\n".join(lines)

    displayed_items = _annotate_display_indices(_queue_window(items))
    grouped: dict[str, list[dict]] = defaultdict(list)
    group_counts: dict[str, int] = defaultdict(int)
    for item in items:
        group_counts[item["artifact_type"]] += 1
    for item in displayed_items:
        grouped[item["artifact_type"]].append(item)

    for artifact_type in ("agent", "skill"):
        group = grouped.get(artifact_type, [])
        if not group:
            continue
        lines.append(
            f"\n{_BOLD}{artifact_type.upper()}S{_RESET} — {group_counts[artifact_type]} pending review"
        )
        for item in group:
            lines.append(f"  {item['display_index']:2}. {_format_nativeness_item(item).strip()}")

    tracker_warnings = _tracker_warning_lines(tracker_integrity)
    if tracker_warnings:
        lines.append(f"\n{_BOLD}TRACKER INTEGRITY{_RESET}")
        for warning in tracker_warnings:
            lines.append(f"  {_YELLOW}⚠{_RESET}  {warning}")

    lines.extend(
        _queue_prompt_lines(
            recommended_item=recommended_item,
            truncated=len(displayed_items) < len(items),
            tracker_integrity=tracker_integrity,
        )
    )

    lines.append("")
    return "\n".join(lines)


