# ── Main ───────────────────────────────────────────────────────────────────────


def main() -> int:
    parser = argparse.ArgumentParser(
        description="Intelligent migration dashboard for Claude→Codex migration",
        formatter_class=argparse.RawDescriptionHelpFormatter,
    )
    mode = parser.add_mutually_exclusive_group()
    mode.add_argument("--status", action="store_true", default=False, help="Show status overview (default)")
    mode.add_argument("--plan", action="store_true", help="Show next batch recommendation")
    mode.add_argument("--review-backlog", action="store_true", help="Show prioritized nativeness review backlog")
    mode.add_argument("--unreviewed", action="store_true", help="Show all migrated artifacts pending nativeness review")
    mode.add_argument("--agent-nativeness", action="store_true", help="Show migrated agents pending nativeness review")
    mode.add_argument("--skill-nativeness", action="store_true", help="Show migrated skills pending nativeness review")
    mode.add_argument("--validate", action="store_true", help="Run validators on migrated skills")
    mode.add_argument("--refresh", action="store_true", help="Re-run tracker --write then show status")
    parser.add_argument("--batch", type=int, default=8, metavar="N", help="Batch size for --plan (default: 8)")
    parser.add_argument(
        "--all",
        dest="show_all",
        action="store_true",
        help="Show all blocked items in --plan; ignored items are always shown",
    )
    parser.add_argument("--no-color", action="store_true", help="Disable ANSI color codes")
    parser.add_argument("--json", action="store_true", dest="json_output", help="Emit structured JSON.")
    args = parser.parse_args()

    if args.no_color:
        global _BOLD, _RESET, _YELLOW, _GREEN, _RED, _DIM
        _BOLD = _RESET = _YELLOW = _GREEN = _RED = _DIM = ""

    refresh_ran = False
    if args.refresh:
        if not args.json_output:
            print("Updating tracker...")
        if not run_tracker_write():
            print("ERROR: Tracker update failed.", file=sys.stderr)
            return 1
        refresh_ran = True

    tracker_data, tracker_integrity, tracker_error = load_tracker_state()
    if args.validate:
        mode_name = "validate"
    elif args.plan:
        mode_name = "plan"
    elif args.review_backlog:
        mode_name = "review_backlog"
    elif args.unreviewed:
        mode_name = "unreviewed"
    elif args.agent_nativeness:
        mode_name = "agent_nativeness"
    elif args.skill_nativeness:
        mode_name = "skill_nativeness"
    else:
        mode_name = "status"
    if tracker_data is None:
        result = _tracker_unavailable_result(mode_name, tracker_error or "Tracker unavailable.", refresh_ran)
        if args.json_output:
            print(json.dumps(result, indent=2))
        else:
            print(
                "\n".join(
                    [
                        "Migration Dashboard",
                        "===================",
                        "",
                        f"Tracker unavailable: {tracker_error}",
                        "Repair: python3 tools/migration_support/tracker.py --write",
                    ]
                )
            )
        return 0

    if args.validate:
        if not args.json_output:
            print("Running validators on migrated skills...")
        results = run_validators(tracker_data)
        environment_readiness = run_environment_readiness_validation()
        result = build_validate_result(
            tracker_data,
            results,
            tracker_integrity=tracker_integrity,
            environment_readiness=environment_readiness,
        )
        if args.json_output:
            print(json.dumps(result, indent=2))
        else:
            print(
                format_validate(
                    results,
                    pending_review_total=result["summary"]["pending_review_total"],
                    tracker_integrity=tracker_integrity,
                    environment_readiness=environment_readiness,
                )
            )
        return 0

    if args.plan:
        plan = build_batch_plan(tracker_data, args.batch, show_all_blocked=args.show_all)
        result = build_plan_result(tracker_data, plan, batch_size=args.batch)
        if args.json_output:
            print(json.dumps(result, indent=2))
        else:
            print(
                format_plan(
                    plan,
                    args.batch,
                    pending_review_total=result["summary"]["pending_review_total"],
                )
            )
        return 0

    if args.review_backlog:
        items = build_review_backlog(tracker_data)
        result = build_review_backlog_result(
            tracker_data,
            items,
            tracker_integrity=tracker_integrity,
        )
        if args.json_output:
            print(json.dumps(result, indent=2))
        else:
            recommended_item = result.get("selection", {}).get("recommended_item")
            print(
                format_review_backlog(
                    items,
                    recommended_item=recommended_item,
                    tracker_integrity=tracker_integrity,
                )
            )
        return 0

    if args.unreviewed:
        items = build_unreviewed_artifacts(tracker_data)
        result = build_unreviewed_result(
            tracker_data,
            items,
            tracker_integrity=tracker_integrity,
        )
        if args.json_output:
            print(json.dumps(result, indent=2))
        else:
            recommended_item = result.get("selection", {}).get("recommended_item")
            print(
                format_unreviewed(
                    items,
                    recommended_item=recommended_item,
                    tracker_integrity=tracker_integrity,
                )
            )
        return 0

    if args.agent_nativeness:
        items = build_agent_nativeness_queue(tracker_data)
        result = build_agent_nativeness_result(
            tracker_data,
            items,
            tracker_integrity=tracker_integrity,
        )
        if args.json_output:
            print(json.dumps(result, indent=2))
        else:
            recommended_item = result.get("selection", {}).get("recommended_item")
            print(
                format_agent_nativeness(
                    items,
                    recommended_item=recommended_item,
                    tracker_integrity=tracker_integrity,
                )
            )
        return 0

    if args.skill_nativeness:
        items = build_skill_nativeness_queue(tracker_data)
        result = build_skill_nativeness_result(
            tracker_data,
            items,
            tracker_integrity=tracker_integrity,
        )
        if args.json_output:
            print(json.dumps(result, indent=2))
        else:
            recommended_item = result.get("selection", {}).get("recommended_item")
            print(
                format_skill_nativeness(
                    items,
                    recommended_item=recommended_item,
                    tracker_integrity=tracker_integrity,
                )
            )
        return 0

    drifted = detect_drift(tracker_data.get("artifacts", []))
    velocity = compute_velocity(tracker_data.get("events", []))
    result = build_status_result(
        tracker_data,
        drifted,
        velocity,
        refresh_ran=refresh_ran,
        tracker_integrity=tracker_integrity,
    )
    if args.json_output:
        print(json.dumps(result, indent=2))
    else:
        print(
            format_status(
                tracker_data,
                drifted,
                velocity,
                tracker_integrity=tracker_integrity,
            )
        )
    return 0


if __name__ == "__main__":
    sys.exit(main())
